module deepbook::margin_borrow {
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use sui::transfer;
    use sui::tx_context::TxContext;
    use deepbook::pool::{Self, Pool};
    use deepbook::position::{Self, DebtPosition};

    /// Borrow USDC from a DeepBook margin pool
    public fun borrow_usdc(
        pool: &mut Pool,
        amount: u64,
        borrower: address,
        ctx: &mut TxContext
    ): Coin<deepbook::usdc::USDC> {
        assert!(pool::available_liquidity(pool) >= amount, 1001);

        let usdc_balance = pool::withdraw_liquidity(pool, amount);
        let usdc_coin = coin::from_balance(usdc_balance, ctx);

        // Record debt position
        let debt_position = position::new_debt_position(borrower, amount);
        transfer::public_transfer(debt_position, borrower);

        usdc_coin
    }
}
