module deepbook_oracle::predict_market {
    use sui::object::{Self, UID};
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::tx_context::{Self, TxContext};
    use deepbook::predict_market::{Self, PredictMarket};
    use oracle::price_feed::{Self, PriceFeed};

    struct PredictMarketWithOracle has key {
        id: UID,
        market: PredictMarket,
        price_feed: PriceFeed,
    }

    public fun create_predict_market_with_oracle(
        market: PredictMarket,
        price_feed: PriceFeed,
        ctx: &mut TxContext,
    ): PredictMarketWithOracle {
        PredictMarketWithOracle {
            id: object::new(ctx),
            market,
            price_feed,
        }
    }

    public fun settle_market_with_oracle(
        predict_market_with_oracle: &mut PredictMarketWithOracle,
        ctx: &mut TxContext,
    ) {
        let price = oracle::price_feed::get_latest_price(predict_market_with_oracle.price_feed);
        deepbook::predict_market::settle(&mut predict_market_with_oracle.market, price, ctx);
    }

    public fun withdraw_proceeds(
        predict_market_with_oracle: &mut PredictMarketWithOracle,
        ctx: &mut TxContext,
    ): Coin<SUI> {
        deepbook::predict_market::withdraw_proceeds(&mut predict_market_with_oracle.market, ctx)
    }

    public fun deposit(
        predict_market_with_oracle: &mut PredictMarketWithOracle,
        coin: Coin<SUI>,
    ) {
        deepbook::predict_market::deposit(&mut predict_market_with_oracle.market, coin);
    }
}

