module deepbook::margin_borrow {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::transfer;
    use sui::tx_context::TxContext;
    use deepbook::pool::{Self, Pool};
    use deepbook::position::{Self, DebtPosition};

    const E_INSUFFICIENT_LIQUIDITY: u64 = 1;

    public fun borrow_usdc(
        pool: &mut Pool,
        amount: u64,
        borrower: address,
        ctx: &mut TxContext
    ): Coin<coin::USDC> {
        assert!(balance::value(&pool.available_liquidity) >= amount, E_INSUFFICIENT_LIQUIDITY);

        let borrowed_coin = balance::split(&mut pool.available_liquidity, amount);
        let usdc_coin = coin::from_balance(borrowed_coin, ctx);

        let debt_position = DebtPosition {
            borrower,
            amount,
            pool_id: object::id(pool),
        };
        position::add_debt_position(&mut pool.debt_positions, debt_position);

        transfer::public_transfer(usdc_coin, borrower);
        usdc_coin
    }
}
