module deepbook::margin_borrow {
    use std::signer;
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use sui::transfer;
    use sui::tx_context::TxContext;
    use deepbook::pool::{Self, Pool};
    use deepbook::types::{USDC};

    /// Borrow USDC from a DeepBook margin pool
    /// Checks available liquidity and records debt position
    public fun borrow_usdc(
        pool: &mut Pool,
        amount: u64,
        borrower: &signer,
        ctx: &mut TxContext
    ): Coin<USDC> {
        assert!(pool.available_liquidity() >= amount, 1001);

        let usdc_balance = pool.borrow_liquidity(amount);
        let usdc_coin = coin::take(&mut usdc_balance, amount, ctx);

        pool.record_debt_position(signer::address_of(borrower), amount);

        usdc_coin
    }

    #[test_only]
    public fun test_borrow_usdc(ctx: &mut TxContext) {
        use sui::test_scenario;

        let scenario = test_scenario::begin(signer::address_of(ctx.sender()));
        let admin = test_scenario::next_sender(&mut scenario);
        let borrower = test_scenario::next_sender(&mut scenario);

        let pool = pool::create_pool<USDC>(&admin, ctx);
        pool::deposit_liquidity(&mut pool, coin::mint(1000000, ctx), ctx);

        let borrowed = borrow_usdc(&mut pool, 500000, &borrower, ctx);
        assert!(coin::value(&borrowed) == 500000, 1);
        assert!(pool.available_liquidity() == 500000, 2);

        test_scenario::end(scenario);
    }
}
