    registry.load_inner();
    let protocol_fees = self.protocol_fees.claim_protocol_fees();
    let coin = self.vault.split(protocol_fees).into_coin(ctx);

    event::emit(ProtocolFeesWithdrawn {
        margin_pool_id: self.id(),
