public(package) fun margin_pool_id(margin_pool_cap: &MarginPoolCap): ID {
    margin_pool_cap.margin_pool_id
}

public(package) fun pool_cap_id(margin_pool_cap: &MarginPoolCap): ID {
    margin_pool_cap.id.to_inner()
}

public(package) fun maintainer_cap_id(maintainer_cap: &MaintainerCap): ID {
    maintainer_cap.id.to_inner()
}

public(package) fun assert_maintainer_cap_valid(
    self: &MarginRegistry,
    maintainer_cap: &MaintainerCap,
) {
    let inner = self.load_inner();
    assert!(
        inner.allowed_maintainers.contains(&maintainer_cap.id.to_inner()),
        EMaintainerCapNotValid,
    );
}

/// Returns the valid price bounds (lower_bound, upper_bound) for a pool.
/// Requires stored price to be fresh (within max_price_age).
/// Aborts if stored price is stale or if price not initialized.
public(package) fun get_price_bounds(
    self: &MarginRegistry,
    pool_id: ID,
    clock: &Clock,
): (u64, u64) {
    self.load_inner();
    let key = CurrentPriceKey { pool_id };

    assert!(self.id.exists_with_type<CurrentPriceKey, CurrentPriceData>(key), EPriceNotInitialized);

    let price_data: &CurrentPriceData = self.id.borrow(key);
    let current_price = price_data.price;
    let price_age_ms = clock.timestamp_ms() - price_data.last_price_update_ms;

    assert!(price_age_ms <= price_data.max_price_age_ms, EPriceUpdateRequired);

    let tolerance = price_data.tolerance;
    let lower_bound = math::mul(current_price, constants::float_scaling() - tolerance);
    let upper_bound = math::mul(current_price, constants::float_scaling() + tolerance);

    (lower_bound, upper_bound)
}

/// Checks if a price is within the configured tolerance of the stored current price.
/// For bids: only checks upper bound (buying above oracle is bad, below is fine).
/// For asks: only checks lower bound (selling below oracle is bad, above is fine).
/// Aborts if price deviation exceeds tolerance, if stored price is stale, or if price not initialized.
public(package) fun assert_price(
    self: &MarginRegistry,
    pool_id: ID,
    price: u64,
    is_bid: bool,
    clock: &Clock,
) {
    let (lower_bound, upper_bound) = self.get_price_bounds(pool_id, clock);
    if (is_bid) {
        assert!(price <= upper_bound, EPriceDeviationTooHigh);
    } else {
        assert!(price >= lower_bound, EPriceDeviationTooHigh);
    };
}

/// Returns the per-pool max limit-order TTL in ms. Falls back to the default
/// when the admin has not set a pool-specific value.
public(package) fun max_order_ttl_ms(self: &MarginRegistry, pool_id: ID): u64 {
    let key = MaxOrderTtlKey(pool_id);
    if (self.id.exists_with_type<MaxOrderTtlKey, u64>(key)) {
        *self.id.borrow<MaxOrderTtlKey, u64>(key)
    } else {
        margin_constants::default_max_order_ttl_ms()
    }
}

/// Clamps a user-supplied limit-order `expire_timestamp` to at most
/// `clock.timestamp_ms() + max_order_ttl_ms(pool_id)`. Applied at every
/// margin limit-order placement site (regular, reduce-only, TPSL) so a
/// resting order cannot outlive the price-protection envelope and become an
/// instrument for stale-price extraction.
public(package) fun clamp_expire_timestamp(
    self: &MarginRegistry,
    pool_id: ID,
    expire_timestamp: u64,
    clock: &Clock,
): u64 {
    let cap = clock.timestamp_ms() + self.max_order_ttl_ms(pool_id);
    if (expire_timestamp > cap) cap else expire_timestamp
}

/// Calculate risk parameters based on leverage factor
fun calculate_risk_ratios(leverage_factor: u64): RiskRatios {
    RiskRatios {
        min_withdraw_risk_ratio: constants::float_scaling() + 4 * leverage_factor, // 1 + 1 = 2x
        min_borrow_risk_ratio: constants::float_scaling() + leverage_factor, // 1 + 0.25 = 1.25x
        liquidation_risk_ratio: constants::float_scaling() +
        leverage_factor / 2, // 1 + 0.125 = 1.125x
        target_liquidation_risk_ratio: constants::float_scaling() +
        leverage_factor, // 1 + 0.25 = 1.25x
    }
}

