    use sui::balance::{Self, Balance};
    use sui::tx_context::TxContext;
    use deepbook::margin_pool::{Self, MarginPool};
    use deepbook::debt_position::{Self, DebtPosition};
    use deepbook::types::{USDC};

    public fun borrow_usdc(
        pool: &mut MarginPool<USDC>,
        amount: u64,
        ctx: &mut TxContext
    ): Coin<USDC> {
        assert!(pool.available_liquidity() >= amount, 0);
        let usdc_coin = coin::take(&mut pool.liquidity, amount);
