        cap: &OracleSettlementCap,
        market: &mut Market,
        oracle_feed: &PriceFeed,
        ctx: &mut TxContext,
    ) {
        let price = oracle::get_price(oracle_feed);
        predict_market::settle(market, price, ctx);
    }

    public fun redeem_settled_position(
        cap: &OracleSettlementCap,
        market: &Market,
        position: Position,
        ctx: &mut TxContext,
    ): Coin<SUI> {
        let (settled, payout) = predict_market::redeem(position, market, ctx);
        assert!(settled, 0);
        payout
    }

    public fun close_oracle_settlement(
        cap: OracleSettlementCap,
        market: &mut Market,
        ctx: &mut TxContext,
    ) {
        let OracleSettlementCap { id, market_id } = cap;
        assert!(predict_market::market_id(market) == market_id, 0);
        object::delete(id);
    }
