module deepbook::margin_borrow {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::object::{Self, UID};
    use sui::tx_context::TxContext;
    use deepbook::pool::Pool;
    use deepbook::margin::{Self, MarginPosition};

    public fun borrow_usdc(
        pool: &mut Pool,
        amount: u64,
        ctx: &mut TxContext
    ): (Coin<USDC>, MarginPosition) {
        assert!(pool.available_liquidity() >= amount, EINSUFFICIENT_LIQUIDITY);

        let usdc_coin = coin::take(&mut pool.usdc_balance, amount, ctx);
        let margin_position = margin::new_position(pool.id, amount, ctx);

        (usdc_coin, margin_position)
    }
}

