module deepbook::margin_borrow {
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use sui::transfer;
    use sui::tx_context::TxContext;
    use deepbook::pool::{Self, Pool};
    use deepbook::position::{Self, DebtPosition};

    public fun borrow_usdc(
        pool: &mut Pool,
        amount: u64,
        borrower: address,
        ctx: &mut TxContext
    ): Coin<deepbook::usdc::USDC> {
        assert!(pool::available_liquidity(pool) >= amount, 100);

        let usdc_balance = pool::withdraw_liquidity(pool, amount);
        let usdc_coin = coin::take(&mut usdc_balance, amount, ctx);

        let debt_position = DebtPosition {
            borrower,
            amount,
            pool_id: object::id(pool),
        };
        position::record_debt(debt_position);

        transfer::public_transfer(usdc_coin, borrower);
        usdc_coin
    }
}
