module deepbook_v3::margin {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::object::{Self, ID, UID};
    use sui::transfer;
    use sui::tx_context::{Self, TxContext};
    use deepbook_v3::pool::{Self, Pool};
    use deepbook_v3::position::{Self, Position};

    struct DebtPosition<phantom Asset> has key, store {
        id: UID,
        amount: u64,
        pool_id: ID,
    }

    public fun borrow_usdc<Asset>(
        pool: &mut Pool<Asset>,
        amount: u64,
        position: &mut Position<Asset>,
        ctx: &mut TxContext
    ): (Coin<Asset>, DebtPosition<Asset>) {
        assert!(pool::available_liquidity(pool) >= amount, 100);

        let coin_balance = balance::split(&mut pool.balance, amount);
        let coin = coin::from_balance(coin_balance, ctx);

        let debt_position = DebtPosition<Asset> {
            id: object::new(ctx),
            amount,
            pool_id: object::id(pool),
        };

        position.total_borrowed = position.total_borrowed + amount;

        (coin, debt_position)
    }

    public fun repay_usdc<Asset>(
        pool: &mut Pool<Asset>,
        coin: Coin<Asset>,
        debt_position: DebtPosition<Asset>,
        position: &mut Position<Asset>,
    ) {
        assert!(object::id(pool) == debt_position.pool_id, 101);

        let coin_balance = coin::into_balance(coin);
        balance::join(&mut pool.balance, coin_balance);

        position.total_borrowed = position.total_borrowed - debt_position.amount;
        let DebtPosition { id, amount: _, pool_id: _ } = debt_position;
        object::delete(id);
    }
}
