#[test]
/// Tests that manager_state returns accurate values with stale oracles.
/// Verifies exact price values, debt amounts, and asset balances.
fun manager_state_returns_accurate_values_with_stale_oracles() {
    let (
        mut scenario,
        mut clock,
        admin_cap,
        maintainer_cap,
        btc_pool_id,
