    base_rate: u64,
    base_slope: u64,
    optimal_utilization: u64,
    excess_slope: u64,
): InterestConfig {
    protocol_config::new_interest_config(base_rate, base_slope, optimal_utilization, excess_slope)
}

/// Helper function to create custom margin pool config
fun create_custom_margin_pool_config(
    supply_cap: u64,
