module deepbook_v3::margin_borrow {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::transfer;
    use sui::tx_context::TxContext;
    use deepbook_v3::pool::{Self, Pool};
    use deepbook_v3::position::{Self, DebtPosition};

    const E_INSUFFICIENT_LIQUIDITY: u64 = 1;

    public fun borrow_usdc(
        pool: &mut Pool,
        amount: u64,
        user: address,
        ctx: &mut TxContext
    ): (Coin<coin::USDC>, DebtPosition) {
        assert!(pool.available_liquidity() >= amount, E_INSUFFICIENT_LIQUIDITY);

        let usdc_coin = coin::take(&mut pool.usdc_reserves, amount, ctx);
        let debt_position = position::new_debt_position(user, amount);

        pool.total_borrowed = pool.total_borrowed + amount;

        (usdc_coin, debt_position)
    }

    public fun repay_usdc(
        pool: &mut Pool,
        debt_position: DebtPosition,
        payment: Coin<coin::USDC>,
        ctx: &mut TxContext
    ) {
        let amount = coin::value(&payment);
        position::validate_debt_position(&debt_position, amount);

        coin::put(&mut pool.usdc_reserves, payment);
        pool.total_borrowed = pool.total_borrowed - amount;

        position::destroy_debt_position(debt_position);
    }
}
