    );

    assert!(mm.conditional_order_ids().length() == 2);

    destroy_2!(sui_price, usdc_price);
    return_shared(pool);
    return_shared(margin_registry);

    // Trigger execution at $2.10
    scenario.next_tx(test_constants::user2());
