/// Return this owner's builder-code index.
public fun index(code: &BuilderCode): u64 {
    code.index
}

/// Return the DUSDC builder fees currently visible for this code.
public fun claimable_builder_fees(root: &AccumulatorRoot, code: &BuilderCode): u64 {
    balance::settled_funds_value<DUSDC>(root, code.id.to_address())
}

/// Claim all settled DUSDC builder fees accumulated for this code.
public fun claim_all_builder_fees(
    code: &mut BuilderCode,
    root: &AccumulatorRoot,
    ctx: &mut TxContext,
): Coin<DUSDC> {
    code.assert_owner(ctx);
    let amount = claimable_builder_fees(root, code);
    let withdrawal = balance::withdraw_funds_from_object<DUSDC>(&mut code.id, amount);
    let coin = balance::redeem_funds(withdrawal).into_coin(ctx);
    if (amount > 0) {
        claim_events::emit_builder_fees_claimed(code.id(), code.owner, amount);
    };
    coin
}

// === Public-Package Functions ===

/// Create and share a derived builder code for the transaction sender.
public(package) fun create_and_share(registry_uid: &mut UID, index: u64, ctx: &TxContext): ID {
    let owner = ctx.sender();
    let code = BuilderCode {
        id: derived_object::claim(registry_uid, BuilderCodeKey(owner, index)),
        owner,
        index,
    };
    let id = code.id();
    transfer::share_object(code);
    account_events::emit_builder_code_created(id, owner, index);
    id
}

// === Private Functions ===

fun assert_owner(code: &BuilderCode, ctx: &TxContext) {
    assert!(ctx.sender() == code.owner, ENotOwner);
}

// === Test-Only Functions ===

/// Construct a `BuilderCode` directly with a chosen owner and index without
/// going through the registry's derived-object path. Useful when a test only
/// needs an object of known shape and does not care about uniqueness.
#[test_only]
public fun new_for_testing(owner: address, index: u64, ctx: &mut TxContext): BuilderCode {
    BuilderCode { id: object::new(ctx), owner, index }
}

/// Destroy a `BuilderCode` created by `new_for_testing` (the production
/// flow shares the object).
#[test_only]
public fun destroy_for_testing(code: BuilderCode) {
    let BuilderCode { id, owner: _, index: _ } = code;
    id.delete();
}

/// Expose the private `assert_owner` so the `ENotOwner` path can be exercised
/// without a real `AccumulatorRoot` (which has no Move-side test constructor).
#[test_only]
public fun assert_owner_for_testing(code: &BuilderCode, ctx: &TxContext) {
    code.assert_owner(ctx)
}

