module deepbook::ewma {
    use sui::math;
    use sui::tx_context::TxContext;
    use deepbook::price_oracle::{Self, PriceOracle};

    /// Struct to hold EWMA state
    struct EWMA has key {
        id: UID,
        current_ema: u64,
        smoothing_factor: u64,
        last_update_timestamp: u64,
    }

    /// Initialize a new EWMA instance
    public fun initialize(
        initial_price: u64,
        smoothing_factor: u64,
        ctx: &mut TxContext
    ): EWMA {
        EWMA {
            id: object::new(ctx),
            current_ema: initial_price,
            smoothing_factor: smoothing_factor,
            last_update_timestamp: sui::clock::timestamp_ms(ctx),
        }
    }

    /// Update EWMA with latest price from oracle
    public fun update(
        ewma: &mut EWMA,
        oracle: &PriceOracle,
        ctx: &TxContext
    ) {
        let current_price = price_oracle::get_price(oracle);
        let current_time = sui::clock::timestamp_ms(ctx);
        let time_elapsed = current_time - ewma.last_update_timestamp;

        // Calculate weight based on time elapsed and smoothing factor
        let weight = math::pow(ewma.smoothing_factor, time_elapsed);
        let inverse_weight = math::pow(100, time_elapsed) - weight;

        // Update EMA
        ewma.current_ema = (weight * ewma.current_ema + inverse_weight * current_price) 
            / math::pow(100, time_elapsed);
        ewma.last_update_timestamp = current_time;
    }

    /// Get current EMA value
    public fun get_current_ema(ewma: &EWMA): u64 {
        ewma.current_ema
    }

    /// Get last update timestamp
    public fun get_last_update(ewma: &EWMA): u64 {
        ewma.last_update_timestamp
    }
}
