module leveraged_long::leveraged_long {
    use sui::balance_manager::BalanceManager;
    use sui::deepbook::DeepBook;
    use sui::math::Math;
    use sui::object::UID;
    use sui::tx_context::TxContext;

    struct LeveragedLongPosition has key {
        id: UID,
        base_asset: BalanceManager,
        quote_asset: BalanceManager,
        leverage: u64,
        health_factor: u64,
    }

    public fun open_leveraged_long_position(
        base_asset: BalanceManager,
        quote_asset: BalanceManager,
        leverage: u64,
        ctx: &mut TxContext
    ): LeveragedLongPosition {
        assert!(leverage <= 3, "Leverage cannot exceed 3x");
        let health_factor = calculate_health_factor(base_asset.balance(), quote_asset.balance(), leverage);
        assert!(health_factor >= 100, "Health factor must be at least 100");
        LeveragedLongPosition {
            id: UID::new(ctx),
            base_asset,
            quote_asset,
            leverage,
            health_factor,
        }
    }

    fun calculate_health_factor(base_balance: u64, quote_balance: u64, leverage: u64): u64 {
        let total_value = base_balance + quote_balance;
        let leveraged_value = total_value * leverage;
        let health_factor = Math::div(leveraged_value, total_value) * 100;
        health_factor
    }

    public fun update_position(
        position: &mut LeveragedLongPosition,
        base_asset: BalanceManager,
        quote_asset: BalanceManager,
        ctx: &mut TxContext
    ) {
        let health_factor = calculate_health_factor(base_asset.balance(), quote_asset.balance(), position.leverage);
        assert!(health_factor >= 100, "Health factor must be at least 100");
        position.base_asset = base_asset;
        position.quote_asset = quote_asset;
        position.health_factor = health_factor;
    }

    public fun close_position(position: LeveragedLongPosition, ctx: &mut TxContext) {
        let LeveragedLongPosition { id, base_asset, quote_asset, leverage: _, health_factor: _ } = position;
        BalanceManager::transfer(base_asset, ctx.sender());
        BalanceManager::transfer(quote_asset, ctx.sender());
        UID::delete(id);
    }
}

