    use deepbook::predict_market::{Self, PredictMarket};
    use deepbook::types::{PredictMarketParams, PredictOutcome};
    use oracle_feed::price_feed::{Self, PriceFeed};

    struct OracleSettlementCap has key {
        id: UID,
        market_id: ID,
    }

    struct SettlementEvent has copy, drop {
        market_id: ID,
        settlement_price: u64,
        winning_outcome: u8,
    }

    public fun initialize_oracle_settlement(
        market: &PredictMarket,
        ctx: &mut TxContext,
    ): OracleSettlementCap {
        OracleSettlementCap {
            id: object::new(ctx),
            market_id: predict_market::id(market),
        }
    }

    public entry fun settle_with_oracle(
        cap: &OracleSettlementCap,
        market: &mut PredictMarket,
        price_feed: &PriceFeed,
        ctx: &mut TxContext,
    ) {
        assert!(predict_market::is_expired(market), 0);
        assert!(!predict_market::is_settled(market), 1);

        let price = price_feed::get_price(price_feed);
        let outcome = if (price >= market.params.strike_price) { 1 } else { 0 };

        predict_market::settle(market, outcome, ctx);

        event::emit(SettlementEvent {
            market_id: cap.market_id,
            settlement_price: price,
            winning_outcome: outcome,
        });
    }

    public entry fun redeem_with_oracle_settlement(
        cap: &OracleSettlementCap,
        market: &PredictMarket,
        position: PredictOutcome,
        ctx: &mut TxContext,
    ) {
        assert!(predict_market::is_settled(market), 0);
        assert!(predict_market::id(market) == cap.market_id, 1);

        let (winning_outcome, _) = predict_market::get_settlement(market);
        let amount = if (position.outcome == winning_outcome) {
            position.amount
        } else {
            0
        };

        let coin = coin::take(&mut position.collateral, amount, ctx);
        transfer::public_transfer(coin, tx_context::sender(ctx));
    }
}
