module deepbook_example::leverage_long {
    use std::option;
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::math;
    use sui::object::{Self, ID, UID};
    use sui::sui::SUI;
    use sui::tx_context::{Self, TxContext};

    use deepbook::balance_manager::{Self, BalanceManager};
    use deepbook::custodian::{Self, Custodian};
    use deepbook::order_book::{Self, OrderBook};
    use deepbook::pool::{Self, Pool};
    use deepbook::types::{Order, OrderType, Side};

    const MAX_LEVERAGE: u64 = 3;
    const MIN_HEALTH_FACTOR: u64 = 1_000_000; // 1.0 in fixed-point

    struct LeveragedPosition<phantom BaseAsset, phantom QuoteAsset> has key, store {
        id: UID,
        order_id: u64,
        base_amount: u64,
        quote_amount: u64,
        leverage: u64,
        health_factor: u64,
    }

    public entry fun open_leveraged_long<BaseAsset, QuoteAsset>(
        balance_manager: &mut BalanceManager,
        order_book: &mut OrderBook<BaseAsset, QuoteAsset>,
        pool: &mut Pool<BaseAsset, QuoteAsset>,
        custodian: &mut Custodian<BaseAsset, QuoteAsset>,
        collateral: Coin<QuoteAsset>,
        leverage: u64,
        price_limit: u64,
        ctx: &mut TxContext,
    ) {
        assert!(leverage > 0 && leverage <= MAX_LEVERAGE, 0);

        let collateral_value = coin::value(&collateral);
        let position_size = math::mul(collateral_value, leverage);

        let (order_id, base_amount, quote_amount) = balance_manager.create_market_order(
            order_book,
            pool,
            custodian,
            Side::Bid,
            position_size,
            OrderType::ImmediateOrCancel,
            option::some(price_limit),
            ctx,
        );

        let health_factor = calculate_health_factor(
            base_amount,
            quote_amount,
            collateral_value,
            leverage
        );
        assert!(health_factor >= MIN_HEALTH_FACTOR, 1);

        let position = LeveragedPosition<BaseAsset, QuoteAsset> {
            id: object::new(ctx),
            order_id,
            base_amount,
            quote_amount,
            leverage,
            health_factor,
        };

        transfer::public_transfer(position, tx_context::sender(ctx));
    }

    fun calculate_health_factor(
        base_amount: u64,
        quote_amount: u64,
        collateral_value: u64,
        leverage: u64,
    ): u64 {
        let position_value = math::mul(base_amount, quote_amount);
        let borrowed_value = math::sub(position_value, collateral_value);
        let min_collateral = math::div(borrowed_value, leverage);

        if (min_collateral == 0) {
            return math::max_u64();
        };

        math::div(math::mul(collateral_value, MIN_HEALTH_FACTOR), min_collateral)
    }

    public entry fun close_position<BaseAsset, QuoteAsset>(
        balance_manager: &mut BalanceManager,
        order_book: &mut OrderBook<BaseAsset, QuoteAsset>,
        pool: &mut Pool<BaseAsset, QuoteAsset>,
        custodian: &mut Custodian<BaseAsset, QuoteAsset>,
        position: LeveragedPosition<BaseAsset, QuoteAsset>,
        ctx: &mut TxContext,
    ) {
        let LeveragedPosition {
            id,
            order_id: _,
            base_amount,
            quote_amount: _,
            leverage: _,
            health_factor: _,
        } = position;

        object::delete(id);

        balance_manager.close_position(
            order_book,
            pool,
            custodian,
            base_amount,
            ctx,
        );
    }
}
