        transfer::public_transfer(liquidation_proceeds, tx_context::sender(ctx));

        emit(LiquidationEvent {
            position_id: object::id(position),
            liquidator: tx_context::sender(ctx),
            proceeds: liquidator_proceeds,
        });

        margin::close_position(position, ctx);
    }
