module deepbook::leveraged_long {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::math;
    use sui::object::{Self, ID, UID};
    use sui::transfer;
    use sui::tx_context::{Self, TxContext};

    use deepbook::balance_manager::{Self, BalanceManager};
    use deepbook::custodian::{Self, Custodian};
    use deepbook::pool::{Self, Pool};
    use deepbook::position::{Self, Position};
    use deepbook::types;

    const MAX_LEVERAGE: u64 = 3;
    const MIN_HEALTH_FACTOR: u64 = 1;

    struct LeveragedPosition has key, store {
        id: UID,
        position_id: ID,
        leverage: u64,
        collateral: Balance<Coin<SUI>>,
    }

    public fun open_leveraged_long_position(
        balance_manager: &mut BalanceManager,
        pool: &mut Pool,
        custodian: &mut Custodian,
        collateral: Coin<SUI>,
        leverage: u64,
        ctx: &mut TxContext,
    ): LeveragedPosition {
        assert!(leverage <= MAX_LEVERAGE, 0);
        let collateral_balance = coin::into_balance(collateral);
        let position = balance_manager::open_position(
            balance_manager,
            pool,
            custodian,
            collateral_balance,
            leverage,
            ctx,
        );

        let position_id = position::id(&position);
        let leveraged_position = LeveragedPosition {
            id: object::new(ctx),
            position_id,
            leverage,
            collateral: balance::zero(),
        };

        leveraged_position
    }

    public fun close_leveraged_long_position(
        leveraged_position: LeveragedPosition,
        balance_manager: &mut BalanceManager,
        pool: &mut Pool,
        custodian: &mut Custodian,
        ctx: &mut TxContext,
    ): Coin<SUI> {
        let position = balance_manager::get_position(
            balance_manager,
            leveraged_position.position_id,
        );
        balance_manager::check_health_factor(position, MIN_HEALTH_FACTOR);

        let (collateral, _) = balance_manager::close_position(
            balance_manager,
            pool,
            custodian,
            position,
            ctx,
        );

        let LeveragedPosition {
            id,
            position_id: _,
            leverage: _,
            collateral: _,
        } = leveraged_position;
        object::delete(id);

        coin::from_balance(collateral, ctx)
    }

    public fun adjust_leverage(
        leveraged_position: &mut LeveragedPosition,
        balance_manager: &mut BalanceManager,
        pool: &mut Pool,
        new_leverage: u64,
        ctx: &mut TxContext,
    ) {
        assert!(new_leverage <= MAX_LEVERAGE, 0);
        let position = balance_manager::get_position(
            balance_manager,
            leveraged_position.position_id,
        );
        balance_manager::check_health_factor(position, MIN_HEALTH_FACTOR);

        balance_manager::adjust_leverage(
            balance_manager,
            pool,
            position,
            new_leverage,
            ctx,
        );
        leveraged_position.leverage = new_leverage;
    }
