module deepbook::black_scholes {
    use std::math;
    use std::fixed_point32;
    use sui::tx_context::TxContext;
    use deepbook::utils;

    const SQRT_2PI: fixed_point32::FixedPoint32 = 0.3989422804014327;
    const ONE_OVER_SQRT2: fixed_point32::FixedPoint32 = 0.7071067811865475;

    public fun calculate_black_scholes(
        spot: fixed_point32::FixedPoint32,
        strike: fixed_point32::FixedPoint32,
        volatility: fixed_point32::FixedPoint32,
        time_to_expiry: fixed_point32::FixedPoint32,
        risk_free_rate: fixed_point32::FixedPoint32,
        is_call: bool,
        _ctx: &mut TxContext
    ): fixed_point32::FixedPoint32 {
        let sqrt_time = fixed_point32::sqrt(time_to_expiry);
        let vol_sqrt_time = fixed_point32::mul(volatility, sqrt_time);

        let log_spot_strike = fixed_point32::ln(fixed_point32::div(spot, strike));
        let rate_plus_vol_sq_half = fixed_point32::add(
            risk_free_rate,
            fixed_point32::div(fixed_point32::mul(volatility, volatility), 2)
        );
        let time_scaled = fixed_point32::mul(rate_plus_vol_sq_half, time_to_expiry);
        let d1_numerator = fixed_point32::add(log_spot_strike, time_scaled);
        let d1 = fixed_point32::div(d1_numerator, vol_sqrt_time);
        let d2 = fixed_point32::sub(d1, vol_sqrt_time);

        let nd1 = cumulative_normal_distribution(d1);
        let nd2 = cumulative_normal_distribution(d2);

        let discount_factor = fixed_point32::exp(
            fixed_point32::mul(
                fixed_point32::neg(time_to_expiry),
                risk_free_rate
            )
        );

        if (is_call) {
            let term1 = fixed_point32::mul(spot, nd1);
            let term2 = fixed_point32::mul(strike, nd2);
            let discounted_term2 = fixed_point32::mul(term2, discount_factor);
            fixed_point32::sub(term1, discounted_term2)
        } else {
            let neg_nd1 = fixed_point32::sub(1, nd1);
            let neg_nd2 = fixed_point32::sub(1, nd2);
            let term1 = fixed_point32::mul(strike, neg_nd2);
            let discounted_term1 = fixed_point32::mul(term1, discount_factor);
            let term2 = fixed_point32::mul(spot, neg_nd1);
            fixed_point32::sub(discounted_term1, term2)
        }
    }

    fun cumulative_normal_distribution(x: fixed_point32::FixedPoint32): fixed_point32::FixedPoint32 {
        let abs_x = fixed_point32::abs(x);
        let t = fixed_point32::div(
            1,
            fixed_point32::add(1, fixed_point32::mul(0.2316419, abs_x))
        );

        let d = fixed_point32::mul(SQRT_2PI, fixed_point32::exp(
            fixed_point32::div(
                fixed_point32::mul(fixed_point32::neg(x), x),
                2
            )
        ));

        let a1 = 0.319381530;
        let a2 = -0.356563782;
        let a3 = 1.781477937;
        let a4 = -1.821255978;
        let a5 = 1.330274429;

        let t_pow_2 = fixed_point32::mul(t, t);
        let t_pow_3 = fixed_point32::mul(t_pow_2, t);
        let t_pow_4 = fixed_point32::mul(t_pow_3, t);
        let t_pow_5 = fixed_point32::mul(t_pow_4, t);

        let polynomial = fixed_point32::add(
            a1,
            fixed_point32::add(
                fixed_point32::mul(a2, t),
                fixed_point32::add(
                    fixed_point32::mul(a3, t_pow_2),
                    fixed_point32::add(
                        fixed_point32::mul(a4, t_pow_3),
                        fixed_point32::mul(a5, t_pow_4)
                    )
                )
            )
        );

        let result = fixed_point32::sub(1, fixed_point32::mul(d, polynomial));

        if (fixed_point32::lt(x, 0)) {
            fixed_point32::sub(1, result)
        } else {
            result
        }
    }
}
