module deepbook_examples::leveraged_long {
    use sui::balance::{Balance, Self};
    use sui::coin::{Coin, Self};
    use sui::math;
    use sui::object::{Self, ID};
    use sui::tx_context::{Self, TxContext};

    use deepbook::balance_manager::{BalanceManager, Self};
    use deepbook::custodian_v2::{Self, CustodianV2};
    use deepbook::order_book::{Self, OrderBook};
    use deepbook::types::{Order, OrderType, Side};

    const MAX_LEVERAGE: u64 = 3;
    const MIN_HEALTH_FACTOR: u64 = 1_000_000; // 1.0 in fixed point

    public fun open_leveraged_long_position<BaseCoin, QuoteCoin>(
        balance_manager: &mut BalanceManager,
        order_book: &mut OrderBook<BaseCoin, QuoteCoin>,
        custodian: &mut CustodianV2<BaseCoin, QuoteCoin>,
        base_coin: Coin<BaseCoin>,
        leverage: u64,
        price: u64,
        ctx: &mut TxContext
    ): (ID, Balance<QuoteCoin>) {
        assert!(leverage <= MAX_LEVERAGE, 0);
        let base_value = math::mul(coin::value(&base_coin), price);
        let quote_value = math::div(math::mul(base_value, leverage), math::pow(10, 8));

        let (position_id, quote_balance) = balance_manager.open_position(
            order_book,
            custodian,
            base_coin,
            Order {
                order_type: OrderType::Limit,
                side: Side::Bid,
                price,
                quantity: coin::value(&base_coin),
                client_order_id: 0,
            },
            ctx
        );

        let health_factor = balance_manager.get_health_factor(position_id);
        assert!(health_factor >= MIN_HEALTH_FACTOR, 1);

        (position_id, quote_balance)
    }

    public fun close_leveraged_long_position<BaseCoin, QuoteCoin>(
        balance_manager: &mut BalanceManager,
        order_book: &mut OrderBook<BaseCoin, QuoteCoin>,
        custodian: &mut CustodianV2<BaseCoin, QuoteCoin>,
        position_id: ID,
        ctx: &mut TxContext
    ): (Coin<BaseCoin>, Coin<QuoteCoin>) {
        let health_factor = balance_manager.get_health_factor(position_id);
        assert!(health_factor >= MIN_HEALTH_FACTOR, 1);

        balance_manager.close_position(
            order_book,
            custodian,
            position_id,
            ctx
        )
    }
}
