    use sui::tx_context::TxContext;
    use sui::object::{Self, UID};
    use sui::transfer;
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use sui::sui::SUI;
    use deepbook::predict_market::{Self, Market, Position};
    use deepbook::oracle::{Self, PriceFeed};

    struct OraclePriceFeed has key {
        id: UID,
        market_id: ID,
        price_feed_id: ID,
        settlement_price: Option<u64>
    }

    public fun initialize(
        market_id: ID,
        price_feed_id: ID,
        ctx: &mut TxContext
    ): OraclePriceFeed {
        OraclePriceFeed {
            id: object::new(ctx),
            market_id,
            price_feed_id,
            settlement_price: none()
        }
    }

    public fun update_settlement_price(
        feed: &mut OraclePriceFeed,
        price_feed: &PriceFeed,
    ) {
        assert!(oracle::is_valid(price_feed), 0);
        let price = oracle::get_price(price_feed);
        feed.settlement_price = some(price);
    }

    public fun settle_market(
        feed: OraclePriceFeed,
        market: &mut Market,
        ctx: &mut TxContext
    ) {
        let OraclePriceFeed {
            id,
            market_id: _,
            price_feed_id: _,
            settlement_price
        } = feed;

        let price = option::extract(&mut settlement_price);
        predict_market::settle(market, price, ctx);
        object::delete(id);
    }

    public fun get_settlement_price(
        feed: &OraclePriceFeed
    ): Option<u64> {
        feed.settlement_price
    }
}
