        let quote_value = math::mul(base_value, leverage);

        balance_manager.check_health_factor(
            base_value,
            quote_value,
            Side::Bid
        );

        let (position, remaining_base) = balance_manager.open_position(
            order_book,
            custodian,
            base_coin,
            leverage,
            Side::Bid,
            ctx
        );

        if (coin::value(&remaining_base) > 0) {
            balance_manager.deposit_base(custodian, remaining_base);
        };

        position
    }
}
```

