module deepbook::predict {
    use std::option;
    use std::signer;
    use std::string;
    use sui::balance;
    use sui::coin;
    use sui::dynamic_field;
    use sui::event;
    use sui::object::{Self, UID};
    use sui::sui::SUI;
    use sui::tx_context::{Self, TxContext};

    use deepbook::pool::{Self, Pool};
    use deepbook::types::{Tick};

    struct PredictPool<OracleT: store + drop, OutcomeT: store + drop> has key, store {
        id: UID,
        pool: Pool,
        strike_price: u64,
        expiry_timestamp_ms: u64,
        oracle: OracleT,
        outcome_a: OutcomeT,
        outcome_b: OutcomeT,
        is_settled: bool
    }

    struct PoolCreated<OracleT: store + drop, OutcomeT: store + drop> has copy, drop {
        pool_id: object::ID,
        strike_price: u64,
        expiry_timestamp_ms: u64,
        oracle: OracleT,
        outcome_a: OutcomeT,
        outcome_b: OutcomeT
    }

    struct PoolSettled<OracleT: store + drop, OutcomeT: store + drop> has copy, drop {
        pool_id: object::ID,
        winning_outcome: OutcomeT
    }

    const EExpired: u64 = 1;
    const ENotExpired: u64 = 2;
    const EAlreadySettled: u64 = 3;
    const EInvalidOracle: u64 = 4;

    public fun create_predict_pool<OracleT: store + drop, OutcomeT: store + drop>(
        strike_price: u64,
        expiry_timestamp_ms: u64,
        oracle: OracleT,
        outcome_a: OutcomeT,
        outcome_b: OutcomeT,
        tick_size: u64,
        lot_size: u64,
        ctx: &mut TxContext
    ): PredictPool<OracleT, OutcomeT> {
        let pool = pool::create(
            option::none(),
            option::none(),
            tick_size,
            lot_size,
            ctx
        );

        let predict_pool = PredictPool {
            id: object::new(ctx),
            pool,
            strike_price,
            expiry_timestamp_ms,
            oracle,
            outcome_a,
            outcome_b,
            is_settled: false
        };

        event::emit(PoolCreated {
            pool_id: object::uid_to_inner(&predict_pool.id),
            strike_price,
            expiry_timestamp_ms,
            oracle,
            outcome_a,
            outcome_b
        });

        predict_pool
    }

    public fun settle_pool<OracleT: store + drop, OutcomeT: store + drop>(
        predict_pool: &mut PredictPool<OracleT, OutcomeT>,
        current_timestamp_ms: u64,
        oracle_result: OracleT,
        ctx: &TxContext
    ) {
        assert!(!predict_pool.is_settled, EAlreadySettled);
        assert!(predict_pool.expiry_timestamp_ms <= current_timestamp_ms, ENotExpired);
        assert!(predict_pool.oracle == oracle_result, EInvalidOracle);

        let winning_outcome = if (current_timestamp_ms >= predict_pool.expiry_timestamp_ms) {
            &predict_pool.outcome_a
        } else {
            &predict_pool.outcome_b
        };

        predict_pool.is_settled = true;

        event::emit(PoolSettled {
            pool_id: object::uid_to_inner(&predict_pool.id),
            winning_outcome: *winning_outcome
        });
    }

    public fun is_settled<OracleT: store + drop, OutcomeT: store + drop>(
        predict_pool: &PredictPool<OracleT, OutcomeT>
    ): bool {
        predict_pool.is_settled
    }

    public fun expiry_timestamp<OracleT: store + drop, OutcomeT: store + drop>(
        predict_pool: &PredictPool<OracleT, OutcomeT>
    ): u64 {
        predict_pool.expiry_timestamp_ms
    }

    public fun strike_price<OracleT: store + drop, OutcomeT: store + drop>(
        predict_pool: &PredictPool<OracleT, OutcomeT>
    ): u64 {
        predict_pool.strike_price
    }
}
