module deepbook::black_scholes {
    use std::math;
    use std::fixed_point32;
    use sui::tx_context::TxContext;
    use deepbook::utils;

    const SQRT_2PI: u128 = 2506628274631000502; // sqrt(2 * PI) in fixed-point

    struct BlackScholesParams has copy, drop {
        spot_price: u64,
        strike_price: u64,
        volatility: u64,  // annualized volatility (e.g., 0.3 for 30%)
        time_to_expiry: u64,  // in years (can be fraction)
        risk_free_rate: u64,  // annual risk-free rate (e.g., 0.05 for 5%)
    }

    public fun calculate_option_price(
        params: BlackScholesParams,
        is_call: bool,
        ctx: &mut TxContext
    ): u64 {
        let (d1, d2) = calculate_d1_d2(params);
        let nd1 = cumulative_normal_distribution(d1);
        let nd2 = cumulative_normal_distribution(d2);

        let discount_factor = fixed_point32::exp(
            fixed_point32::mul(
                fixed_point32::from_u64(params.risk_free_rate),
                fixed_point32::from_u64(params.time_to_expiry).neg()
            )
        );

        if (is_call) {
            let price = fixed_point32::mul(
                fixed_point32::from_u64(params.spot_price),
                nd1
            ) - fixed_point32::mul(
                fixed_point32::mul(
                    fixed_point32::from_u64(params.strike_price),
                    discount_factor
                ),
                nd2
            );
            fixed_point32::ceil(price)
        } else {
            let price = fixed_point32::mul(
                fixed_point32::mul(
                    fixed_point32::from_u64(params.strike_price),
                    discount_factor
                ),
                fixed_point32::sub(fixed_point32::from_u64(1), nd2)
            ) - fixed_point32::mul(
                fixed_point32::from_u64(params.spot_price),
                fixed_point32::sub(fixed_point32::from_u64(1), nd1)
            );
            fixed_point32::ceil(price)
        }
    }

    fun calculate_d1_d2(params: BlackScholesParams): (fixed_point32::FixedPoint32, fixed_point32::FixedPoint32) {
        let sqrt_time = fixed_point32::sqrt(fixed_point32::from_u64(params.time_to_expiry));
        let vol_sqrt_time = fixed_point32::mul(
            fixed_point32::from_u64(params.volatility),
            sqrt_time
        );

        let spot_over_strike = fixed_point32::div(
            fixed_point32::from_u64(params.spot_price),
            fixed_point32::from_u64(params.strike_price)
        );
        let ln_spot_strike = fixed_point32::ln(spot_over_strike);

        let r_plus_vol_sq_half = fixed_point32::add(
            fixed_point32::from_u64(params.risk_free_rate),
            fixed_point32::div(
                fixed_point32::mul(
                    fixed_point32::from_u64(params.volatility),
                    fixed_point32::from_u64(params.volatility)
                ),
                fixed_point32::from_u64(2)
            )
        );
        let numerator = fixed_point32::add(
            ln_spot_strike,
            fixed_point32::mul(
                r_plus_vol_sq_half,
                fixed_point32::from_u64(params.time_to_expiry)
            )
        );

        let d1 = fixed_point32::div(numerator, vol_sqrt_time);
        let d2 = fixed_point32::sub(d1, vol_sqrt_time);

        (d1, d2)
    }

    fun cumulative_normal_distribution(x: fixed_point32::FixedPoint32): fixed_point32::FixedPoint32 {
        let abs_x = fixed_point32::abs(x);
        let t = fixed_point32::div(
            fixed_point32::from_u64(1),
            fixed_point32::add(
                fixed_point32::from_u64(1),
                fixed_point32::mul(abs_x, fixed_point32::from_u64(2316419))
            )
        );

        let d = fixed_point32::div(
            fixed_point32::from_u64(1),
            fixed_point32::sqrt(
                fixed_point32::from_u64(SQRT_2PI)
            )
        );
        let e = fixed_point32::exp(
            fixed_point32::mul(
                fixed_point32::from_u64(-1),
                fixed_point32::div(
                    fixed_point32::mul(abs_x, abs_x),
                    fixed_point32::from_u64(2)
                )
