        let total_liquidity = margin_pool::total_liquidity(pool_id);
        let total_shares = margin_pool::total_shares(pool_id);

        let shares_to_mint = if (total_shares == 0) {
            usdc_value
        } else {
            (usdc_value * total_shares) / total_liquidity
        };

        lp_shares::mint(shares_to_mint, ctx)
    }
}
