    use deepbook::margin_position;
    use deepbook::pool;
    use deepbook::utils;

    struct LiquidationEvent has copy, drop {
        position_id: ID,
        liquidator: address,
        protocol_fee: u64,
        liquidator_reward: u64,
    }

    public fun liquidate_position<BaseAsset, QuoteAsset>(
        pool: &mut pool::Pool<BaseAsset, QuoteAsset>,
        position: &mut margin_position::MarginPosition<BaseAsset, QuoteAsset>,
        margin_account: &mut margin_account::MarginAccount<BaseAsset, QuoteAsset>,
        ctx: &mut TxContext
    ) {
        assert!(margin_position::is_undercollateralized(position), 0);

        let position_value = margin_position::position_value(position, pool);
        let debt_value = margin_position::debt_value(position);
        let collateral_value = margin_position::collateral_value(position);

        let protocol_fee = math::mul_div(
            position_value - debt_value,
            pool.liquidation_fee_numerator,
            pool.liquidation_fee_denominator
        );

        let liquidator_reward = math::mul_div(
            position_value - debt_value,
            pool.liquidation_reward_numerator,
            pool.liquidation_reward_denominator
        );

        let remaining_value = position_value - debt_value - protocol_fee - liquidator_reward;

        // Transfer protocol fee to protocol
        let protocol_coin = coin::take(&mut margin_account.protocol_fees, ctx);
        let protocol_fee_coin = coin::split(protocol_coin, protocol_fee, ctx);
        transfer::public_transfer(protocol_fee_coin, pool.protocol_fee_address);

        // Transfer reward to liquidator
        let liquidator_coin = coin::withdraw<QuoteAsset>(margin_account, liquidator_reward, ctx);
        transfer::public_transfer(liquidator_coin, tx_context::sender(ctx));

        // Return remaining collateral to position owner
        if (remaining_value > 0) {
            let remaining_coin = coin::withdraw<QuoteAsset>(margin_account, remaining_value, ctx);
            transfer::public_transfer(remaining_coin, position.owner);
        }

        // Close the position
        margin_position::close_position(position, margin_account);

        // Emit liquidation event
        event::emit(LiquidationEvent {
            position_id: object::id(position),
            liquidator: tx_context::sender(ctx),
            protocol_fee,
            liquidator_reward,
        });
    }
}
