        ctx: &mut TxContext
    ): (Coin<coin::USDC>, DebtPosition) {
        assert!(pool.available_liquidity() >= amount, 100);

        let usdc_coin = pool.withdraw_liquidity(amount, ctx);
        let debt_position = position::new_debt_position(borrower, amount, ctx);

