    struct PredictionMarketPool<phantom T> has key {
        id: UID,
        strike_price: u64,
        expiry_timestamp: u64,
        long_pool: Pool<T>,
        short_pool: Pool<T>,
        oracle: Oracle<T>,
        is_settled: bool,
        settlement_price: u64
    }

    struct PredictionMarketTicket<phantom T> has store, drop {
        is_long: bool,
        amount: u64
    }

    public fun create_prediction_market_pool<T>(
        strike_price: u64,
        expiry_timestamp: u64,
        oracle: Oracle<T>,
        ctx: &mut TxContext
    ): PredictionMarketPool<T> {
        let long_pool = pool::create<T>(ctx);
        let short_pool = pool::create<T>(ctx);

        PredictionMarketPool<T> {
            id: object::new(ctx),
            strike_price,
            expiry_timestamp,
            long_pool,
            short_pool,
            oracle,
            is_settled: false,
            settlement_price: 0
        }
    }

    public fun buy_long<T>(
        pool: &mut PredictionMarketPool<T>,
        payment: Coin<T>,
        ctx: &mut TxContext
    ): (PredictionMarketTicket<T>, Coin<T>) {
        let (ticket, change) = pool::swap_exact_coin_for_liquidity(
            &mut pool.long_pool,
            payment,
            ctx
        );

        (
            PredictionMarketTicket<T> {
                is_long: true,
                amount: coin::value(&ticket)
            },
            change
        )
    }

    public fun buy_short<T>(
        pool: &mut PredictionMarketPool<T>,
        payment: Coin<T>,
        ctx: &mut TxContext
    ): (PredictionMarketTicket<T>, Coin<T>) {
        let (ticket, change) = pool::swap_exact_coin_for_liquidity(
            &mut pool.short_pool,
            payment,
            ctx
        );

        (
            PredictionMarketTicket<T> {
                is_long: false,
                amount: coin::value(&ticket)
            },
            change
        )
    }

    public fun settle<T>(
        pool: &mut PredictionMarketPool<T>,
        ctx: &mut TxContext
    ) {
        assert!(!pool.is_settled, 0);
        assert!(sui::clock::timestamp_ms(ctx) >= pool.expiry_timestamp, 1);

        let price = oracle::get_price(&pool.oracle);
        pool.settlement_price = price;
        pool.is_settled = true;
    }

    public fun redeem<T>(
        pool: &mut PredictionMarketPool<T>,
        ticket: PredictionMarketTicket<T>,
        ctx: &mut TxContext
    ): Coin<T> {
        assert!(pool.is_settled, 0);

        let payout_amount = if ticket.is_long {
            if pool.settlement_price > pool.strike_price {
                math::mul_div(
                    ticket.amount,
                    pool.settlement_price,
                    pool.strike_price
                )
            } else {
                0
            }
        } else {
            if pool.settlement_price < pool.strike_price {
                math::mul_div(
                    ticket.amount,
                    pool.strike_price,
                    pool.settlement_price
                )
            } else {
                0
            }
        };

        if ticket.is_long {
            pool::remove_liquidity(
                &mut pool.long_pool,
                payout_amount,
                ctx
            )
        } else {
            pool::remove_liquidity(
                &mut pool.short_pool,
                payout_amount,
                ctx
            )
        }
    }
}
