module deepbook::margin_borrow {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::tx_context::TxContext;
    use deepbook::pool::{Pool, PoolCapability};
    use deepbook::types::{USDC, MarginPosition};

    public fun borrow_usdc(
        pool: &mut Pool<USDC>,
        amount: u64,
        capability: &PoolCapability,
        ctx: &mut TxContext
    ): (Coin<USDC>, MarginPosition) {
        assert!(balance::value(&pool.available_liquidity) >= amount, 1001);

        let borrowed_coin = coin::take(&mut pool.available_liquidity, amount, ctx);
        let debt_position = MarginPosition {
            borrower: tx_context::sender(ctx),
            amount,
            timestamp: tx_context::epoch(ctx),
        };

        pool.debt_positions.push_back(debt_position);

        (borrowed_coin, debt_position)
    }
}

