module deepbook::margin_borrow {
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use sui::transfer;
    use deepbook::pool::{Self, Pool};
    use deepbook::position::{Self, Position};
    use deepbook::usdc::USDC;

    public fun borrow_usdc(
        pool: &mut Pool,
        position: &mut Position,
        amount: u64,
        ctx: &mut TxContext
    ): Coin<USDC> {
        assert!(pool.available_liquidity >= amount, 100);
        pool.available_liquidity = pool.available_liquidity - amount;

        let usdc_balance = balance::withdraw(&mut pool.usdc_reserves, amount);
        let usdc_coin = coin::from_balance(usdc_balance, ctx);

        position.debt_amount = position.debt_amount + amount;
        position.last_update_timestamp = timestamp::now_seconds();

        usdc_coin
    }
}
