module deepbook::ewma {
    use sui::balance::Balance;
    use sui::coin::Coin;
    use sui::object::{Self, UID};
    use sui::tx_context::TxContext;
    use deepbook::price_oracle::PriceOracle;

    struct EWMA has key {
        id: UID,
        alpha: u64,
        current_average: u64,
    }

    public fun initialize(alpha: u64, ctx: &mut TxContext): EWMA {
        EWMA {
            id: object::new(ctx),
            alpha,
            current_average: 0,
        }
    }

    public fun update_average(ewma: &mut EWMA, price_oracle: &PriceOracle) {
        let current_price = price_oracle.get_price();
        let alpha = ewma.alpha;
        let previous_average = ewma.current_average;

        let new_average = (alpha * current_price + (100 - alpha) * previous_average) / 100;
        ewma.current_average = new_average;
    }

    public fun get_average(ewma: &EWMA): u64 {
        ewma.current_average
    }
}

