module deepbook_v3::leveraged_long {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::math;
    use sui::tx_context::TxContext;
    use deepbook_v3::balance_manager::{Self, BalanceManager};
    use deepbook_v3::market::{Market, OrderSide};
    use deepbook_v3::position::{Position, PositionType};

    const MAX_LEVERAGE: u64 = 3;
    const MIN_HEALTH_FACTOR: u64 = 110; // 1.1 represented as percentage

    public fun open_leveraged_long_position<Base, Quote>(
        balance_manager: &mut BalanceManager,
        market: &Market<Base, Quote>,
        base_coin: Coin<Base>,
        leverage: u64,
        ctx: &mut TxContext
    ): Position<Base, Quote> {
        assert!(leverage <= MAX_LEVERAGE, 0);
        let base_value = coin::value(&base_coin);
        let quote_value = math::mul(base_value, leverage);

        let (position, health_factor) = balance_manager::open_position_with_leverage(
            balance_manager,
            market,
            base_coin,
            quote_value,
            OrderSide::Bid,
            PositionType::LeveragedLong,
            ctx
        );

        assert!(health_factor >= MIN_HEALTH_FACTOR, 1);
        position
    }

    public fun close_leveraged_long_position<Base, Quote>(
        balance_manager: &mut BalanceManager,
        market: &Market<Base, Quote>,
        position: Position<Base, Quote>,
        ctx: &mut TxContext
    ): (Coin<Base>, Balance<Quote>) {
        balance_manager::close_position(balance_manager, market, position, ctx)
    }

    public fun check_position_health<Base, Quote>(
        balance_manager: &BalanceManager,
        position: &Position<Base, Quote>
    ): u64 {
        balance_manager::get_position_health_factor(balance_manager, position)
    }
}
