module deepbook_v3::leveraged_long {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::math;
    use sui::object::{Self, ID};
    use sui::tx_context::TxContext;

    use deepbook_v3::balance_manager::{Self, BalanceManager};
    use deepbook_v3::deepbook::{Self, DeepBook};
    use deepbook_v3::position::{Self, Position};

    const MAX_LEVERAGE: u64 = 3;
    const MIN_HEALTH_FACTOR: u64 = 110; // 1.1 represented as percentage

    public fun open_leveraged_long_position(
        balance_manager: &mut BalanceManager,
        deepbook: &mut DeepBook,
        collateral: Coin<SUI>,
        leverage: u64,
        price_limit: u64,
        ctx: &mut TxContext
    ): (Position, Balance<SUI>) {
        assert!(leverage <= MAX_LEVERAGE, 0);
        assert!(leverage > 0, 1);

        let collateral_value = coin::value(&collateral);
        let position_size = math::mul(collateral_value, leverage);

        // Verify health factor remains acceptable
        let health_factor = balance_manager::calculate_health_factor(
            balance_manager,
            position_size,
            collateral_value
        );
        assert!(health_factor >= MIN_HEALTH_FACTOR, 2);

        // Open position through DeepBook
        let (position, quote_balance) = deepbook::open_position(
            deepbook,
            collateral,
            position_size,
            price_limit,
            ctx
        );

        // Register position with BalanceManager
        balance_manager::register_position(
            balance_manager,
            &position,
            position_size,
            leverage
        );

        (position, quote_balance)
    }

    public fun calculate_health_factor(
        balance_manager: &BalanceManager,
        position_size: u64,
        collateral_value: u64
    ): u64 {
        let max_loss = position_size - collateral_value;
        if (max_loss == 0) {
            return math::max_value<u64>();
        };
        math::div(math::mul(collateral_value, 100), max_loss)
    }
}
