module deepbook::margin_liquidation {
    use sui::balance;
    use sui::coin;
    use sui::object;
    use sui::transfer;
    use sui::tx_context::TxContext;
    use deepbook::margin::{Self, Position};
    use deepbook::protocol_fees;

    struct LiquidationEvent has copy, drop {
        position_id: object::ID,
        liquidator: address,
        proceeds: u64,
    }

    public entry fun liquidate_position(position_id: object::ID, ctx: &mut TxContext) {
        let position = margin::borrow_position(position_id);
        assert!(is_undercollateralised(&position), 0);

        let proceeds = calculate_proceeds(&position);
        let protocol_fee = protocol_fees::calculate_fee(proceeds);

        let coin = coin::take(&mut position.collateral, ctx);
        let (liquidator_coin, protocol_coin) = coin::split(coin, proceeds - protocol_fee, ctx);

        transfer::transfer(liquidator_coin, ctx.sender());
        transfer::public_transfer(protocol_coin, protocol_fees::protocol_address());

        margin::close_position(position_id, ctx);

        emit_event(LiquidationEvent {
            position_id,
            liquidator: ctx.sender(),
            proceeds,
        });
    }

    fun is_undercollateralised(position: &Position): bool {
        let collateral_value = balance::value(&position.collateral);
        let maintenance_margin = position.leverage * position.maintenance_margin_ratio;
        collateral_value < maintenance_margin
    }

    fun calculate_proceeds(position: &Position): u64 {
        balance::value(&position.collateral)
    }

    fun emit_event(event: LiquidationEvent) {
        sui::event::emit(event);
    }
}

