module deepbook::ewma {
    use sui::math;
    use sui::tx_context::TxContext;
    use deepbook::price_oracle::{Self, PriceOracle};

    struct EWMA has key {
        id: UID,
        alpha: u64,
        current_ema: u64,
        last_update_timestamp: u64,
    }

    public fun initialize(
        ctx: &mut TxContext,
        alpha: u64,
        initial_price: u64,
    ): EWMA {
        EWMA {
            id: object::new(ctx),
            alpha,
            current_ema: initial_price,
            last_update_timestamp: sui::clock::timestamp_ms(ctx),
        }
    }

    public fun update(
        ewma: &mut EWMA,
        new_price: u64,
        ctx: &TxContext,
    ) {
        let current_timestamp = sui::clock::timestamp_ms(ctx);
        let time_elapsed = current_timestamp - ewma.last_update_timestamp;

        // Prevent division by zero and handle first update
        if (time_elapsed == 0) {
            return;
        };

        let alpha_scaled = math::mul(ewma.alpha, time_elapsed) / 1000;
        let one_minus_alpha = 1000 - alpha_scaled;

        let new_ema_part = math::mul(alpha_scaled, new_price) / 1000;
        let old_ema_part = math::mul(one_minus_alpha, ewma.current_ema) / 1000;

        ewma.current_ema = new_ema_part + old_ema_part;
        ewma.last_update_timestamp = current_timestamp;
    }

    public fun get_current_ema(ewma: &EWMA): u64 {
        ewma.current_ema
    }

    public fun update_from_oracle(
        ewma: &mut EWMA,
        oracle: &PriceOracle,
        ctx: &TxContext,
    ) {
        let current_price = price_oracle::get_price(oracle);
        update(ewma, current_price, ctx);
    }
}
