    use deepbook::position::{Self, Position};
    use deepbook::types::{OrderSide, OrderStatus, Self};

    const MAX_LEVERAGE: u64 = 3;
    const MIN_HEALTH_FACTOR: u64 = 1_000_000; // 1.0 in fixed-point

    public fun open_leveraged_long_position<BaseCoinType, QuoteCoinType>(
        market: &mut Market<BaseCoinType, QuoteCoinType>,
        custodian: &mut Custodian<BaseCoinType, QuoteCoinType>,
        base_coin: Coin<BaseCoinType>,
        quote_coin: Coin<QuoteCoinType>,
        leverage: u64,
        ctx: &mut TxContext,
