            custodian,
            base_coin,
            quote_coin,
            ctx,
        );

        let total_collateral = math::checked_add(
            math::checked_mul(base_value, leverage),
            quote_value,
        );

        let position_value = position::notional_value(&position, market);
        let health_factor = math::checked_div(
            math::checked_mul(position_value, MIN_HEALTH_FACTOR),
            total_collateral,
        );

        assert!(health_factor >= MIN_HEALTH_FACTOR, 1);

        let order_id = market::place_limit_order(
            market,
            order::new_limit_order(
                position.position_id,
                OrderSide::Bid,
                position.size,
                position.price,
                option::none(),
                ctx,
            ),
        );

        (position, base_balance, quote_balance)
    }

