// market_oracle_update_prices_tests.move.

module deepbook_oracle_integration::predict_market {
    use sui::tx_context::TxContext;
    use sui::coin::Coin;
    use sui::balance::Balance;
    use sui::object::{Self, UID};
    use deepbook::predict_market::{Self, PredictMarket};
    use deepbook::oracle::OraclePriceFeed;
    use deepbook::utils::math;

    struct PredictMarketWithOracle has key {
        id: UID,
        market: PredictMarket,
        oracle: OraclePriceFeed,
    }

    public fun create_predict_market_with_oracle(
        market: PredictMarket,
        oracle: OraclePriceFeed,
        ctx: &mut TxContext,
    ): PredictMarketWithOracle {
        PredictMarketWithOracle {
            id: object::new(ctx),
            market,
            oracle,
        }
    }

    public fun settle_market_with_oracle(
        market_with_oracle: &mut PredictMarketWithOracle,
        ctx: &mut TxContext,
    ) {
        let oracle_price = market_with_oracle.oracle.get_price();
        let market = &mut market_with_oracle.market;
        predict_market::settle(market, oracle_price, ctx);
    }

    public fun update_oracle_price(
        market_with_oracle: &mut PredictMarketWithOracle,
        new_price: u64,
    ) {
        market_with_oracle.oracle.update_price(new_price);
    }

    public fun get_current_price(
        market_with_oracle: &PredictMarketWithOracle,
    ): u64 {
        market_with_oracle.oracle.get_price()
    }

    public fun calculate_payout(
        market_with_oracle: &PredictMarketWithOracle,
        stake: Balance<Coin<sui::sui::SUI>>,
    ): u64 {
        let current_price = market_with_oracle.oracle.get_price();
        let market = &market_with_oracle.market;
        predict_market::calculate_payout(market, stake, current_price)
    }
}

