module deepbook::oracle_price_feed {
    use sui::tx_context::TxContext;
    use sui::object::{Self, UID};
    use sui::transfer;
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use sui::sui::SUI;
    use deepbook::predict_market::{Self, Market, Position};
    use deepbook::oracle::{Self, PriceFeed};

    struct OracleSettlementCap has key {
        id: UID,
        market_id: ID,
    }

    public fun initialize(
        market_id: ID,
        ctx: &mut TxContext,
    ): OracleSettlementCap {
        OracleSettlementCap {
            id: object::new(ctx),
            market_id,
        }
    }

    public fun settle_with_oracle(
        cap: &mut OracleSettlementCap,
        market: &mut Market<SUI>,
        price_feed: &PriceFeed,
        ctx: &mut TxContext,
    ) {
        let oracle_price = oracle::get_price(price_feed);
        let settlement_price = predict_market::normalize_price(oracle_price);

        let (long_coins, short_coins) = predict_market::settle(market, settlement_price, ctx);

        if (balance::value(&long_coins) > 0) {
            let long_coin = coin::from_balance(long_coins, ctx);
            transfer::public_transfer(long_coin, predict_market::get_long_position_owner(market));
        };

        if (balance::value(&short_coins) > 0) {
            let short_coin = coin::from_balance(short_coins, ctx);
            transfer::public_transfer(short_coin, predict_market::get_short_position_owner(market));
        };
    }

    public fun upgrade_cap(
        cap: OracleSettlementCap,
        new_market_id: ID,
        ctx: &mut TxContext,
    ): OracleSettlementCap {
        let OracleSettlementCap { id, market_id: _ } = cap;
        OracleSettlementCap {
            id,
            market_id: new_market_id,
        }
    }
