module deepbook::oracle_price_feed {
    use sui::clock::{Self, Clock};
    use sui::transfer;
    use sui::tx_context::TxContext;
    use deepbook::predict_market::{Self, Market, Position};
    use deepbook::oracle_adapter::{Self, PriceFeed};

    /// Settles a predict market using the latest price from the oracle feed.
    public fun settle_with_oracle_price(
        market: &mut Market,
        oracle_feed: &PriceFeed,
        clock: &Clock,
        ctx: &mut TxContext
    ) {
        let current_timestamp = clock::timestamp_seconds(clock);
        assert!(current_timestamp >= market.expiry_time, "Market not expired");

        let (price, decimals) = oracle_adapter::get_latest_price(oracle_feed, clock);
        let scaled_price = (price as u128) * (10u128).pow((18 - decimals) as u64);

        predict_market::settle(market, scaled_price, ctx);
    }

    /// Claims settled positions using oracle price settlement.
    public fun claim_settled_position(
        market: &Market,
        position: Position,
        oracle_feed: &PriceFeed,
        clock: &Clock,
