const EXPIRY_MS: u64 = 100_000;
const NOW_MS: u64 = 10_000;
const FIRST_SVI_SOURCE_TIMESTAMP_MS: u64 = 1_000;
const SECOND_SVI_SOURCE_TIMESTAMP_MS: u64 = 2_000;
