module deepbook::predict_oracle {
    use std::option;
    use sui::balance;
    use sui::coin;
    use sui::event;
    use sui::object::{Self, UID};
    use sui::sui::SUI;
    use sui::tx_context::{Self, TxContext};
    use deepbook::predict_market::{Self, PredictionMarket, PredictionOutcome};
    use deepbook::oracle::{Self, PriceFeed};

    /// Oracle-settled prediction market
    struct OraclePredictionMarket has key, store {
        id: UID,
        market: PredictionMarket,
        oracle_feed_id: ID,
        expiry_timestamp_ms: u64,
        settlement_price: option::Option<u64>
    }

    /// Event emitted when prediction market is created
    struct OracleMarketCreated has copy, drop {
        market_id: ID,
        oracle_feed_id: ID,
        expiry_timestamp_ms: u64
    }

    /// Event emitted when prediction market is settled
    struct OracleMarketSettled has copy, drop {
        market_id: ID,
        settlement_price: u64
    }

    /// Create new oracle-settled prediction market
    public fun create(
        oracle_feed_id: ID,
        expiry_timestamp_ms: u64,
        ctx: &mut TxContext
    ): OraclePredictionMarket {
        let market = predict_market::create(ctx);
        let market_id = object::id(&market);

        event::emit(OracleMarketCreated {
            market_id,
            oracle_feed_id,
            expiry_timestamp_ms
        });

        OraclePredictionMarket {
            id: object::new(ctx),
            market,
            oracle_feed_id,
            expiry_timestamp_ms,
            settlement_price: option::none()
        }
    }

    /// Settle prediction market using oracle price feed
    public fun settle(market: &mut OraclePredictionMarket, ctx: &TxContext) {
        assert!(!option::is_some(&market.settlement_price), 0);
        assert!(tx_context::epoch_timestamp_ms(ctx) >= market.expiry_timestamp_ms, 1);

        let price_feed = oracle::get_price_feed(market.oracle_feed_id);
        let settlement_price = oracle::current_price(&price_feed);

        market.settlement_price = option::some(settlement_price);
        predict_market::settle(&mut market.market, PredictionOutcome::Price(settlement_price));

        event::emit(OracleMarketSettled {
            market_id: object::id(&market.market),
            settlement_price
        });
    }

    /// Claim winnings from settled prediction market
    public fun claim(
        market: &mut OraclePredictionMarket,
        position: coin::Coin<PredictionOutcome>,
        ctx: &mut TxContext
    ): coin::Coin<SUI> {
        predict_market::claim(&mut market.market, position, ctx)
    }

    /// Get current settlement price (if available)
    public fun settlement_price(market: &OraclePredictionMarket): option::Option<u64> {
        market.settlement_price
    }
}
