module deepbook_example::leveraged_long {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::math;
    use sui::object::{Self, ID};
    use sui::tx_context::TxContext;

    use deepbook::balance_manager::{Self, BalanceManager};
    use deepbook::custodian_v2::{Self, CustodianV2};
    use deepbook::market::{Market, Self};
    use deepbook::order::{Self, Order};
    use deepbook::pool::{Pool, Self};
    use deepbook::types::{OrderSide, OrderType};

    const MAX_LEVERAGE: u64 = 3;
    const MIN_HEALTH_FACTOR: u64 = 1_000_000; // 1.0 in 6 decimal precision

    public fun open_leveraged_long_position<Base, Quote>(
        balance_manager: &mut BalanceManager,
        market: &Market<Base, Quote>,
        base_coin: Coin<Base>,
        leverage: u64,
        ctx: &mut TxContext
    ): (ID, Balance<Quote>) {
        assert!(leverage <= MAX_LEVERAGE, 0);
        let base_value = coin::value(&base_coin);
        let quote_value = pool::get_quote_value(market, base_value, OrderSide::Bid);

        // Calculate required collateral and borrowed amount
        let collateral = base_value;
        let borrowed = (quote_value * leverage) - quote_value;

        // Health factor check
        let health_factor = calculate_health_factor(collateral, borrowed);
        assert!(health_factor >= MIN_HEALTH_FACTOR, 1);

        // Deposit collateral
        let base_balance = balance::from_coin(base_coin);
        let custodian = balance_manager::get_custodian(balance_manager);
        let custodian_id = custodian_v2::id(custodian);
        let base_balance_id = balance::id(&base_balance);
        custodian_v2::deposit(custodian, base_balance_id, base_balance);

        // Borrow quote tokens
        let quote_balance = balance_manager::borrow(balance_manager, borrowed, ctx);

        // Create order
        let order = order::new_limit_order(
            market,
            OrderSide::Bid,
            OrderType::ImmediateOrCancel,
            base_value,
            quote_value * leverage,
            ctx
        );

        // Place order
        let order_id = market::place_order(market, order, ctx);

        (order_id, quote_balance)
    }

    fun calculate_health_factor(collateral: u64, borrowed: u64): u64 {
        if (borrowed == 0) {
            return math::max_u64();
        };
        (collateral * 1_000_000) / borrowed
    }

    public fun close_leveraged_long_position<Base, Quote>(
        balance_manager: &mut BalanceManager,
        market: &Market<Base, Quote>,
        order_id: ID,
        quote_balance: Balance<Quote>,
        ctx: &mut TxContext
    ) {
        // Get order and check if it's filled
        let order = market::get_order_by_id(market, order_id);
        assert!(order::is_filled(&order), 2);

        // Get filled amounts
        let (base_filled, quote_filled) = order::get_filled_amounts(&order);

        // Repay borrowed amount
        let custodian = balance_manager::get_custodian(balance_manager);
        let quote_balance_id = balance::id(&quote_balance);
        custodian_v2::withdraw(custodian, quote_balance_id, quote_filled);
        balance_manager::repay(balance_manager, quote_balance);

        // Withdraw collateral
        let base_balance = custodian_v2::withdraw_base<Base>(custodian, base_filled, ctx);
        let base_coin = balance::into_coin(base_balance);
        transfer::public_transfer(base_coin, tx_context::sender(ctx));
    }
}
