    assert_eq!(bob_sui.value(), TWENTY_FIVE_SUI);
    assert_eq!(bob_deep.value(), 0);
    assert_eq!(vault.incentive_sui_locked(), FIFTY_SUI);
    assert_eq!(vault.incentive_sui_balance(), TWENTY_FIVE_SUI);

    destroy(alice_lp);
    destroy(bob_dusdc);
    destroy(bob_sui);
    destroy(bob_deep);
