module deepbook::usdc_liquidity {
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use sui::transfer;
    use sui::tx_context::{Self, TxContext};
    use deepbook::pool::{Self, Pool};
    use deepbook::shares::{Self, Shares};
    use deepbook::usdc::USDC;

    public fun supply_usdc_liquidity(
        pool: &mut Pool<USDC>,
        usdc_coins: vector<Coin<USDC>>,
        ctx: &mut TxContext
    ): (Balance<USDC>, Shares) {
        let total_amount = coin::destroy_zero(usdc_coins);
        let usdc_balance = balance::increase_supply(total_amount);

        let (shares_minted, new_pool_state) = pool.supply(usdc_balance, ctx);
        *pool = new_pool_state;

        (usdc_balance, shares_minted)
    }

    public entry fun supply_usdc_liquidity_entry(
        pool: &mut Pool<USDC>,
        usdc_coins: vector<Coin<USDC>>,
        ctx: &mut TxContext
    ) {
        let (usdc_balance, shares) = supply_usdc_liquidity(pool, usdc_coins, ctx);
        transfer::public_transfer(shares, tx_context::sender(ctx));
        transfer::public_transfer(usdc_balance, tx_context::sender(ctx));
    }
}
