    admin_cap: admin::AdminCap,
    vault: PoolVault,
    manager: PredictManager,
) {
    destroy(manager);
    destroy(admin_cap);
    test::return_shared(vault);
    registry::destroy_registry_drop_for_testing(reg);
    scenario.end();
}

