module deepbook::borrow_usdc {
    use sui::balance::{Balance, Self};
    use sui::coin::{Coin, Self};
    use sui::event;
    use sui::object::{Self, UID};
    use sui::transfer;
    use sui::tx_context::{Self, TxContext};
    use deepbook::margin_pool::{MarginPool, Self};
    use deepbook::types::{DebtPosition, Self};

    struct BorrowReceipt has key, store {
        id: UID,
        amount: u64,
    }

    public fun borrow_usdc(pool: &mut MarginPool, amount: u64, ctx: &mut TxContext): (Coin<USDC>, BorrowReceipt) {
        assert!(pool.available_liquidity() >= amount, 1001);

        let usdc_coin = pool.withdraw(amount, ctx);
        let debt_position = DebtPosition::new(amount, ctx);
        pool.record_debt_position(&debt_position);

        event::emit(BorrowEvent {
            borrower: tx_context::sender(ctx),
            amount,
            pool_id: object::id(pool),
        });

        let receipt = BorrowReceipt {
            id: object::new(ctx),
            amount,
        };

        (usdc_coin, receipt)
    }

    struct BorrowEvent has copy, drop {
        borrower: address,
        amount: u64,
        pool_id: ID,
    }
}

