        let price = price_feed::get_price(price_feed, market.price_feed_id);
        predict_market.settle(price, ctx);
    }

    public fun withdraw_proceeds(
        market: OraclePriceFeedMarket,
        predict_market: &mut PredictMarket,
        ctx: &mut TxContext,
    ): Coin<SUI> {
        let proceeds = predict_market.withdraw_proceeds(ctx);
        transfer::public_transfer(market, ctx.sender());
        proceeds
    }
