    use deepbook::predict_market::{Self, Market, Position};
    use deepbook::oracle::{Self, PriceFeed};

    struct OracleSettlementCap has key {
        id: UID,
        market_id: ID,
    }

    public fun initialize_oracle_settlement(
        market: &mut Market,
        oracle_feed: &PriceFeed,
        ctx: &mut TxContext,
    ): OracleSettlementCap {
        OracleSettlementCap {
            id: object::new(ctx),
            market_id: predict_market::market_id(market),
        }
    }

    public fun settle_with_oracle_price(
        cap: &OracleSettlementCap,
        market: &mut Market,
        oracle_feed: &PriceFeed,
        long_positions: vector<Position>,
        short_positions: vector<Position>,
        ctx: &mut TxContext,
    ) {
        let current_price = oracle::get_price(oracle_feed);
        let (long_coins, short_coins) = predict_market::settle_at_price(
            market,
            long_positions,
            short_positions,
            current_price,
            ctx,
        );

        // Distribute settled coins back to users
        while (!vector::is_empty(&long_coins)) {
            let coin = vector::pop_back(&mut long_coins);
            transfer::public_transfer(coin, predict_market::position_owner(&coin));
        };

        while (!vector::is_empty(&short_coins)) {
            let coin = vector::pop_back(&mut short_coins);
            transfer::public_transfer(coin, predict_market::position_owner(&coin));
        };
    }

    public fun destroy_oracle_settlement_cap(cap: OracleSettlementCap) {
        let OracleSettlementCap { id, market_id: _ } = cap;
        object::delete(id);
    }
}
