    let ctx = &mut tx_context::dummy();
    let (mut vault, cap) = setup(ctx);

    vault.deposit(&cap, coin::mint_for_testing<SUI>(1000, ctx));
    let withdrawn = vault.withdraw<SUI>(&cap, 1000, ctx);
