module deepbook::margin_liquidation {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::event;
    use sui::object::{Self, ID, UID};
    use sui::transfer;
    use sui::tx_context::{Self, TxContext};

    use deepbook::margin_account::{Self, MarginAccount};
    use deepbook::margin_math;
    use deepbook::margin_types;
    use deepbook::pool::{Self, Pool};

    struct LiquidationEvent has copy, drop {
        liquidated_account: address,
        liquidator: address,
        collateral_amount: u64,
        debt_amount: u64,
        protocol_fee: u64
    }

    public fun liquidate_undercollateralised_position(
        pool: &mut Pool,
        margin_account: &mut MarginAccount,
        liquidator_coin: Coin<margin_types::QuoteCoin>,
        ctx: &mut TxContext
    ) {
        assert!(margin_math::is_undercollateralised(margin_account), 0);

        let (collateral_value, debt_value) = margin_math::get_position_values(pool, margin_account);
        let shortfall = debt_value - collateral_value;

        let liquidator_balance = coin::into_balance(liquidator_coin);
        let protocol_fee = margin_math::calculate_liquidation_fee(shortfall);

        let liquidation_amount = shortfall + protocol_fee;
        assert!(balance::value(&liquidator_balance) >= liquidation_amount, 1);

        let liquidator_share = balance::split(&mut liquidator_balance, shortfall);
        let protocol_share = balance::split(&mut liquidator_balance, protocol_fee);

        margin_account::settle_debt(margin_account, pool, shortfall);
        margin_account::withdraw_collateral(margin_account, collateral_value);

        transfer::public_transfer(coin::from_balance(liquidator_share), tx_context::sender(ctx));
        transfer::public_transfer(coin::from_balance(protocol_share), pool.protocol_fee_address);

        event::emit(LiquidationEvent {
            liquidated_account: object::address_from_uid(&margin_account.id),
            liquidator: tx_context::sender(ctx),
            collateral_amount: collateral_value,
            debt_amount: debt_value,
            protocol_fee: protocol_fee
        });
    }
}
